 class ProductContext : DbContext
 {
     public DbSet<Product> Products => Set<Product>();
     protected override void OnModelCreating(ModelBuilder modelBuilder)
     {
         // Preserve EF Core 8 discriminator property name so existing documents
         // (which have "Discriminator": "Product") remain readable, and direct
         // SQL queries referencing c.Discriminator keep working.
         modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

         // Preserve EF Core 8 compound id format ("Product|123") so existing
         // 500K documents remain accessible via FindAsync / point-reads.
         modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

         // HasIndex removed — Cosmos provider now throws at startup.
         // Manage indexing via the container's indexing policy in Azure Portal / Bicep.
         modelBuilder.Entity<Product>().ToContainer("Products");
     }
 }
